POLICY_VIOLATION_PATTERNS = [
    re.compile(r"(synthesis route|step.by.step.*instructions|exact (ratio|proportions|dose))", re.I),
    re.compile(r"(api.key|password|secret|token).{0,30}(is|=|:)", re.I),
    re.compile(r"(send|post|upload|transmit).{0,40}(http|ftp|webhook|endpoint)", re.I),
    re.compile(r"(ignore|override|bypass|disregard).{0,30}(rule|policy|restrict|guideline)", re.I),
]

@dataclass
class PolicyCheckResult:
    allowed: bool
    violations: list[str]

def check_output_policy(response_text: str) -> PolicyCheckResult:
    violations = []
    for pattern in POLICY_VIOLATION_PATTERNS:
        m = pattern.search(response_text)
        if m:
            violations.append(m.group(0))
    return PolicyCheckResult(allowed=len(violations) == 0, violations=violations)

class SafeAgent:
    def __init__(self, model_fn):
        self._model = model_fn

    def run(self, user_message: str) -> str:
        scan = scan_for_jailbreak(user_message)
        if scan.blocked:
            return f"Request declined: {scan.reason}"

        response = self._model(user_message)

        policy = check_output_policy(response)
        if not policy.allowed:
            _audit_log("POLICY_VIOLATION", violations=policy.violations, input=user_message)
            return "I can not help with that."

        return response

from dataclasses import dataclass, field
from collections import defaultdict

@dataclass
class SessionBehavior:
    turn_count: int = 0
    refusal_count: int = 0
    jailbreak_signals_per_turn: list[int] = field(default_factory=list)

class BehaviorMonitor:
    ESCALATION_WINDOW = 5
    SIGNAL_SPIKE_THRESHOLD = 3
    REFUSAL_STORM_THRESHOLD = 4

    def __init__(self):
        self._sessions: dict[str, SessionBehavior] = defaultdict(SessionBehavior)

    def record_turn(self, session_id: str, signals: list, refusal: bool) -> bool:
        """Returns True if the session should be escalated or locked out."""
        b = self._sessions[session_id]
        b.turn_count += 1
        b.jailbreak_signals_per_turn.append(len(signals))
        if refusal:
            b.refusal_count += 1
        else:
            b.refusal_count = 0

        recent = b.jailbreak_signals_per_turn[-self.ESCALATION_WINDOW:]
        if len(recent) >= 3 and all(s > 0 for s in recent):
            return True  # persistent jailbreak probing across turns

        if b.refusal_count >= self.REFUSAL_STORM_THRESHOLD:
            return True  # repeated refusals may signal adversarial session

        if len(signals) >= self.SIGNAL_SPIKE_THRESHOLD:
            return True  # single-turn spike

        return False
